Drupal.behaviors.cardBehaviour={attach(e){const t=e.querySelectorAll(".card");for(let e=0;e<t.length;e+=1){let a,c;const n=t[e],r=n.querySelector("a");n.addEventListener("mousedown",()=>{a=+new Date}),n.addEventListener("mouseup",e=>{const t=e.which&&![1,2].indexOf(e.which);c=+new Date,c-a<200&&r&&t&&r.click()})}}};